import { Component, computed, inject, OnInit, signal } from '@angular/core';
import { ActivatedRoute, ParamMap, Router, RouterLink } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { AssignmentService } from '../../../core/services/assignment.service';
import { CourseService } from '../../../core/services/course.service';
import { AuthService } from '../../../core/services/auth.service';
import { ToastService } from '../../../core/services/toast.service';
import { AssignmentDetailDto } from '../../../core/models/assignment.models';
import { CourseNavComponent } from '../../../shared/course-nav/course-nav';
import { ModuleNavBarComponent } from '../../../shared/module-nav-bar/module-nav-bar';

/**
 * Assignment view + submission — /courses/:courseId/assignments/:assignmentId.
 * The learner-facing item in the Canvas-style module flow: instructions,
 * a submission box, and the shared Prev/Next bar. Reached from module items.
 */
@Component({
  selector: 'app-assignment-detail',
  standalone: true,
  imports: [RouterLink, FormsModule, CourseNavComponent, ModuleNavBarComponent],
  template: `
    <div class="course-layout">
      <app-course-nav [courseId]="courseId()" [active]="isAdmin() ? 'assignments' : 'modules'" />

      <main class="course-main">
        <a [routerLink]="['/courses', courseId()]" class="back-link">
          <span class="material-icons">arrow_back</span> Back to course
        </a>

        @if (loading()) {
          <div class="loading-spinner"><div class="spinner"></div></div>
        } @else if (assignment(); as a) {
          <div class="card">
            <h1 class="ad-title">{{ a.title }}</h1>
            <p class="ad-meta">
              @if (a.dueDate) { <span>Due {{ a.dueDate.slice(0, 10) }}</span> · }
              <span>{{ a.maxPoints }} points</span>
              @if (a.isRequired) { · <span>Required</span> }
            </p>

            @if (a.instructions) {
              <div class="ad-instructions">{{ a.instructions }}</div>
            } @else {
              <p class="ad-empty">No instructions provided.</p>
            }

            @if (!isAdmin()) {
              <div class="ad-submit">
                <h3>Your submission</h3>
                @if (submitError()) { <div class="alert alert-danger">{{ submitError() }}</div> }
                @if (submitted()) {
                  <div class="alert alert-success">Assignment submitted successfully!</div>
                } @else {
                  <div class="form-group">
                    <textarea [(ngModel)]="submissionText" rows="8" placeholder="Type your answer here…"></textarea>
                  </div>
                  <button class="btn btn-primary" (click)="submit(a)"
                          [disabled]="submitting() || !submissionText.trim()">
                    {{ submitting() ? 'Submitting…' : 'Submit Assignment' }}
                  </button>
                }
              </div>
            }

            <app-module-nav-bar [courseId]="courseId()" [itemId]="itemId()" />
          </div>
        }
      </main>
    </div>
  `,
  styleUrl: './assignment-detail.scss',
})
export class AssignmentDetailComponent implements OnInit {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private aSvc = inject(AssignmentService);
  private cSvc = inject(CourseService);
  private auth = inject(AuthService);
  private toast = inject(ToastService);

  readonly courseId = signal(0);
  readonly assignment = signal<AssignmentDetailDto | null>(null);
  readonly loading = signal(true);
  readonly itemId = signal<number | null>(null);
  readonly submitting = signal(false);
  readonly submitted = signal(false);
  readonly submitError = signal('');
  readonly isAdmin = computed(() => this.auth.hasRole('PlatformAdmin', 'Instructor'));

  submissionText = '';

  ngOnInit(): void {
    this.route.paramMap.subscribe(pm => this.loadFromRoute(pm));
  }

  private loadFromRoute(pm: ParamMap): void {
    this.courseId.set(Number(pm.get('courseId')));
    const qp = this.route.snapshot.queryParamMap;
    const itemId = qp.get('itemId');
    this.itemId.set(itemId !== null ? Number(itemId) : null);
    this.submissionText = '';
    this.submitted.set(false);
    this.submitError.set('');

    this.loading.set(true);
    this.aSvc.getById(Number(pm.get('assignmentId'))).subscribe({
      next: a => { this.assignment.set(a); this.loading.set(false); },
      error: (e: Error) => {
        this.loading.set(false);
        this.toast.error(`Failed to open assignment: ${e.message}`);
        this.router.navigate(['/courses', this.courseId()]);
      },
    });
  }

  submit(a: AssignmentDetailDto): void {
    this.submitting.set(true);
    this.submitError.set('');
    this.aSvc.submit(a.id, { textContent: this.submissionText }).subscribe({
      next: () => {
        this.submitting.set(false);
        this.submitted.set(true);
        // Submitting satisfies the module item — mark it done so progress tracks.
        const itemId = this.itemId();
        if (itemId !== null) this.cSvc.markModuleItemComplete(itemId, 0).subscribe({ error: () => {} });
      },
      error: (e: Error) => { this.submitting.set(false); this.submitError.set(e.message); },
    });
  }
}
